function TabPanel(props){
	const {value, index, content} = props
	const statusCss = {float:'right', marginTop:10, marginLeft:40, paddingLeft:10, paddingRight:10, paddingTop:5, paddingBottom:5, borderRadius:50}
	function statusProgress(x){
		switch(x){
			case 1:
				return {color:'#6cf55d',text:"Up-Running"}
				break;
			case 2:
				return {color:'#e6e6e6',text:"in-Progress"}
				break;
			case 3:
				return {color:'#ffdf52',text:"Discontinued"}
				break;
		}
	}
	var projectStatus = statusProgress(content.status)
	return (
		<div
			role="tabpanel"
			hidden={value !== index}
			style={{position:'relative', width:'100%'}}
		>
			<Grid container alignItems="center" style={{paddingTop:100}}>
				<Grid item md={2} lg={2} sm={5}>
					<img src={content.icon} style={{width:index == 1 ? '100%':'80%', borderRadius:50}}/>
				</Grid>
				<Grid item md={8} lg={8} sm={7} style={{paddingLeft:20}}>
					<Grid container>
						<Grid item>
							<Typography style={{fontSize:'2rem',float:'left'}}>{content.title}</Typography>
							<div style={{backgroundColor:projectStatus.color, ...statusCss}}>{ projectStatus.text }</div>
						</Grid>
					</Grid>
					<Typography style={{fontSize:'1rem', paddingTop:30}}>{content.desc}</Typography>
				</Grid>
			</Grid>
			{/* <div style={{paddingTop:70, paddingBottom:400, overflowY:'scroll', height:100}}> */}
				<Grid container style={{marginTop:70, marginBottom:400, overflowZ:'scroll', overflowY:'hidden', width:"100%"}}>
					{content.content(props.setShowBackdrop)}
				</Grid>
			{/* </div> */}
		</div>
	)
}
